   185→static void convert_rgb_to_uyvy(uint8_t *rgb_buffer, uint8_t *yuv_buffer,
   186→				freenect_frame_mode mode)
   187→{
   188→	int x,y;
   189→	for (y = 0; y < mode.height; y++) {
   190→		for (x = 0; x < mode.width; x+=2) {
   191→			int pos = y * mode.width + x;
   192→			uint8_t *rgb0 = rgb_buffer + pos * 3;
   193→			uint8_t *rgb1 = rgb_buffer + (pos + 1) * 3;
   194→			float y0 = (0.257f * rgb0[0]) + (0.504f * rgb0[1]) + (0.098f * rgb0[2]) + 16;
   195→			float u0 = -(0.148f * rgb0[0]) - (0.291f * rgb0[1]) + (0.439f * rgb0[2]) + 128;
   196→			float v0 = (0.439f * rgb0[0]) - (0.368f * rgb0[1]) - (0.071f * rgb0[2]) + 128;
   197→
   198→			float y1 = (0.257f * rgb1[0]) + (0.504f * rgb1[1]) + (0.098f * rgb1[2]) + 16;
   199→			float u1 = -(0.148f * rgb1[0]) - (0.291f * rgb1[1]) + (0.439f * rgb1[2]) + 128;
   200→			float v1 = (0.439f * rgb1[0]) - (0.368f * rgb1[1]) - (0.071f * rgb1[2]) + 128;
   201→
   202→			uint8_t *uyvy = yuv_buffer + pos * 2;
   203→
   204→			uyvy[0] = (u0+u1)/2.f;
   205→			uyvy[1] = y0;
   206→			uyvy[2] = (v0+v1)/2.f;
   207→			uyvy[3] = y1;
   208→		}
   209→	}
   210→}
