   474→static void read_device_info(freenect_device *dev)
   475→{
   476→	char fn[512];
   477→	snprintf(fn, sizeof(fn), "%s/device.json", input_path);
   478→
   479→	/* We silently return if this file is missing for compatibility with
   480→	 * older recordings and applications that don't depend on registration
   481→	 * info.
   482→	 */
   483→	JSON_Value *js = json_parse_file(fn);
   484→        if (!js)
   485→		return;
   486→
   487→	JSON_Object *reg_info = json_object_get_object(json_object(js), "reg_info");
